﻿const input = $json.body ?? $json;
const metricsIn = input.metrics ?? {};
const incidents = Array.isArray(input.incidents) ? input.incidents : [];

const fallbackNotification = {
  channel: 'both',
  slack: {
    webhook_url: '__REDACTED_SLACK_WEBHOOK__'
  },
  telegram: {
    bot_token: '__REDACTED_TELEGRAM_BOT_TOKEN__',
    chat_id: '__REDACTED_TELEGRAM_CHAT_ID__'
  }
};

function pickNonEmpty(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return '';
}

const incomingNotification = input.notification ?? {};
const incomingChannel = String(incomingNotification.channel ?? '').trim().toLowerCase();
const resolvedChannel = incomingChannel || fallbackNotification.channel;
const wantsSlack = resolvedChannel === 'slack' || resolvedChannel === 'both';
const wantsTelegram = resolvedChannel === 'telegram' || resolvedChannel === 'both';

const notification = {
  channel: resolvedChannel,
  slack: {
    webhook_url: wantsSlack
      ? pickNonEmpty(incomingNotification?.slack?.webhook_url, fallbackNotification.slack.webhook_url)
      : ''
  },
  telegram: {
    bot_token: wantsTelegram
      ? pickNonEmpty(incomingNotification?.telegram?.bot_token, fallbackNotification.telegram.bot_token)
      : '',
    chat_id: wantsTelegram
      ? pickNonEmpty(incomingNotification?.telegram?.chat_id, fallbackNotification.telegram.chat_id)
      : ''
  }
};

const metrics = {
  contracts_evaluated: Number(metricsIn.contracts_evaluated ?? 0),
  ads_evaluated: Number(metricsIn.ads_evaluated ?? 0),
  paused_success_count: Number(metricsIn.paused_success_count ?? 0),
  paused_error_count: Number(metricsIn.paused_error_count ?? 0),
  expired_unpaused_count: Number(metricsIn.expired_unpaused_count ?? 0),
  preventive_48h_count: Number(metricsIn.preventive_48h_count ?? 0),
  duration_ms: Number(metricsIn.duration_ms ?? 0)
};

const executionStatus = String(input.execution_status ?? input.status ?? 'unknown').toLowerCase();
const isCritical = metrics.expired_unpaused_count > 0;
const hasWarnSignals = metrics.preventive_48h_count > 0 || executionStatus !== 'success' || metrics.paused_error_count > 0 || incidents.length > 0;

let severity = 'INFO';
if (isCritical) {
  severity = 'CRITICAL';
} else if (hasWarnSignals) {
  severity = 'WARN';
}

const correlationId = String(input.correlation_id ?? input.execution_id ?? ('ops-' + Date.now()));
const timezone = input.timezone ?? 'America/Argentina/Buenos_Aires';

return [{
  json: {
    ...input,
    correlation_id: correlationId,
    execution_status: executionStatus,
    timezone,
    incidents,
    metrics,
    notification,
    derived: {
      severity,
      is_critical: isCritical,
      execution_mode: String(input.execution_mode ?? 'scheduled').toLowerCase(),
      executed_at: input.executed_at ?? new Date().toISOString()
    }
  }
}];

﻿const m = $json.metrics ?? {};
const incidents = Array.isArray($json.incidents) ? $json.incidents : [];

const pausedOk = Number(m.paused_success_count ?? 0);
const pausedErr = Number(m.paused_error_count ?? 0);
const contractsReviewed = Number(m.contracts_evaluated ?? 0);
const durationSec = (Number(m.duration_ms ?? 0) / 1000).toFixed(1);

function uniq(values) {
  return [...new Set(values.filter(Boolean))];
}

const incidentInfluencers = incidents
  .map((it) => String(it?.influencer ?? '').trim())
  .filter(Boolean);
const contextInfluencers = Array.isArray($json.context?.influencers)
  ? $json.context.influencers.map((x) => String(x || '').trim())
  : [];
const influencers = uniq([...contextInfluencers, ...incidentInfluencers]);

const expiredInfluencersCount = influencers.length || Number(m.expired_unpaused_count ?? 0);
const influencersInline = influencers.length
  ? ` (${influencers.map((name) => `${name.replace(/^@/, '')}`).join(', ')})`
  : '';

const firstFailure = incidents.find((it) => {
  const code = String(it?.code ?? '').trim();
  const type = String(it?.type ?? '').toLowerCase();
  return code || type.includes('error') || type.includes('fail');
}) ?? incidents[0] ?? {};

const failureInfluencer = String(firstFailure.influencer ?? '').trim();
const failureInfluencerText = failureInfluencer ? ` (Influencer: ${failureInfluencer.replace(/^@/, '')})` : '';
const reasonCode = pausedErr > 0 ? String(firstFailure.code ?? 'UNKNOWN_ERROR') : 'SIN_ERRORES_REPORTADOS';

const executionId = String($json.execution_id ?? 'N/A');
const correlationId = String($json.correlation_id ?? 'N/A');

const telegramText = [
  '<b>ADSGuardian: ALERTA CRITICA</b>',
  '',
  '<b>Resumen de Accion:</b>',
  `Ads Pausadas: ${pausedOk}`,
  `Influencers Vencidos: ${expiredInfluencersCount}${influencersInline}`,
  '',
  '<b>Estado de errores:</b>',
  `Fallas al pausar: ${pausedErr} Ad${pausedErr === 1 ? '' : 's'}${failureInfluencerText}`,
  `Motivo: ${reasonCode}`,
  '',
  '<b>Metricas de sesion:</b>',
  `- Total contratos revisados: ${contractsReviewed}`,
  `- Duracion: ${durationSec}s`,
  '',
  `Scan ID: <code>${executionId}</code>`,
  `Correlation ID: <code>${correlationId}</code>`
].join('\n');

const slackPayload = {
  text: 'ADSGuardian: ALERTA CRITICA',
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: 'ADSGuardian: ALERTA CRITICA', emoji: false } },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: [
          '*Resumen de Accion:*',
          `Ads Pausadas: ${pausedOk}`,
          `Influencers Vencidos: ${expiredInfluencersCount}${influencersInline}`
        ].join('\n')
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: [
          '*Estado de errores:*',
          `Fallas al pausar: ${pausedErr} Ad${pausedErr === 1 ? '' : 's'}${failureInfluencerText}`,
          `Motivo: ${reasonCode}`
        ].join('\n')
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: [
          '*Metricas de sesion:*',
          `- Total contratos revisados: ${contractsReviewed}`,
          `- Duracion: ${durationSec}s`
        ].join('\n')
      }
    },
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: `Scan ID: \`${executionId}\` | Correlation: \`${correlationId}\`` }
      ]
    }
  ]
};

return [{
  json: {
    ...$json,
    message_text: telegramText,
    message_slack: slackPayload,
    message_telegram: telegramText
  }
}];

﻿const m = $json.metrics ?? {};
const incidents = Array.isArray($json.incidents) ? $json.incidents : [];
const severity = String($json.derived?.severity ?? 'INFO').toUpperCase();

const executionId = String($json.execution_id ?? 'N/A');
const correlationId = String($json.correlation_id ?? 'N/A');
const preventiveCount = Number(m.preventive_48h_count ?? 0);

function uniq(values) {
  return [...new Set(values.filter(Boolean))];
}

const contextInfluencers = Array.isArray($json.context?.influencers)
  ? $json.context.influencers.map((x) => String(x || '').trim())
  : [];
const incidentInfluencers = incidents
  .map((it) => String(it?.influencer ?? '').trim())
  .filter(Boolean);
const influencers = uniq([...contextInfluencers, ...incidentInfluencers]);

const pausedByInfluencerRaw = Array.isArray($json.context?.paused_by_influencer)
  ? $json.context.paused_by_influencer
  : [];
const pausedByInfluencer = pausedByInfluencerRaw
  .map((it) => ({
    influencer: String(it?.influencer ?? '').trim().replace(/^@/, ''),
    ads_paused: Number(it?.ads_paused ?? 0)
  }))
  .filter((it) => it.influencer && Number.isFinite(it.ads_paused) && it.ads_paused > 0);
const pausedSummaryLines = pausedByInfluencer.length
  ? pausedByInfluencer.map((it) => `- Se pausaron exitosamente ${it.ads_paused} ads del influencer ${it.influencer}`).join('\n')
  : '';

const influencersTelegram = influencers.length
  ? influencers.map((name) => `- ${name.replace(/^@/, '')}`).join('\n')
  : '- Sin detalle de influencers';

const influencersSlack = influencers.length
  ? influencers.map((name) => `- ${name.replace(/^@/, '')}`).join('\n')
  : '- Sin detalle de influencers';

const crmUrl = String($json.context?.crm_url ?? $json.context?.sheet_url ?? '').trim();
const telegramLinkLine = crmUrl ? `Ver en CRM/Sheet: ${crmUrl}` : 'Ver en CRM/Sheet';
const slackLinkLine = crmUrl ? `<${crmUrl}|Ver en CRM/Sheet>` : 'Ver en CRM/Sheet';

let telegramText;
let slackPayload;

if (severity === 'INFO') {
  if (pausedSummaryLines) {
    telegramText = [
      '<b>ADSGuardian: Sistema OK</b>',
      '',
      pausedSummaryLines,
      '',
      `Scan finalizado | ID: <code>${executionId}</code>`
    ].join('\n');
  } else {
    telegramText = [
      '<b>ADSGuardian: Sistema OK</b>',
      '',
      'Estado: Sin novedades.',
      '',
      'No se detectaron contratos vencidos ni proximos a vencer.',
      '',
      `Scan finalizado | ID: <code>${executionId}</code>`
    ].join('\n');
  }

  slackPayload = {
    text: 'ADSGuardian: Sistema OK',
    blocks: [
      { type: 'header', text: { type: 'plain_text', text: 'ADSGuardian: Sistema OK', emoji: false } },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: pausedSummaryLines
            ? [
              pausedSummaryLines
            ].join('\n')
            : [
              'Estado: Sin novedades.',
              'No se detectaron contratos vencidos ni proximos a vencer.'
            ].join('\n')
        }
      },
      { type: 'context', elements: [{ type: 'mrkdwn', text: `Scan finalizado | ID: \`${executionId}\`` }] }
    ]
  };
} else {
  const contractsAtRisk = preventiveCount > 0 ? preventiveCount : influencers.length;

  telegramText = [
    '<b>ADSGuardian: Alerta de Vencimiento (48h)</b>',
    '',
    `Contratos proximos a expirar: <b>${contractsAtRisk}</b>`,
    '',
    '<b>Influencers en riesgo:</b>',
    influencersTelegram,
    '',
    'Tenes 48 horas para renovar el contrato o actualizar la fecha en el sistema para evitar la pausa automatica.',
    '',
    telegramLinkLine,
    '',
    `Scan finalizado | ID: <code>${executionId}</code>`,
    `Correlation ID: <code>${correlationId}</code>`
  ].join('\n');

  slackPayload = {
    text: 'ADSGuardian: Alerta de Vencimiento (48h)',
    blocks: [
      { type: 'header', text: { type: 'plain_text', text: 'ADSGuardian: Alerta de Vencimiento (48h)', emoji: false } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Contratos proximos a expirar:* ${contractsAtRisk}` } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Influencers en riesgo:*\n${influencersSlack}` } },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: 'Tenes 48 horas para renovar el contrato o actualizar la fecha en el sistema para evitar la pausa automatica.'
        }
      },
      { type: 'section', text: { type: 'mrkdwn', text: slackLinkLine } },
      { type: 'context', elements: [{ type: 'mrkdwn', text: `Scan ID: \`${executionId}\` | Correlation: \`${correlationId}\`` }] }
    ]
  };
}

return [{
  json: {
    ...$json,
    message_text: telegramText,
    message_slack: slackPayload,
    message_telegram: telegramText
  }
}];

return [{
  json: {
    event: 'ops_notification_channel_error',
    channel: String($json.notification?.channel ?? 'unknown').toLowerCase(),
    severity: $json.derived?.severity ?? 'WARN',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Fallo de env?o de notificaci?n. MVP sin fallback autom?tico entre canales.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_sent',
    channel: 'slack',
    severity: $json.derived?.severity ?? 'INFO',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Notificaci?n enviada por Slack.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_sent',
    channel: 'telegram',
    severity: $json.derived?.severity ?? 'INFO',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Notificaci?n enviada por Telegram.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_channel_unsupported',
    channel: String($json.notification?.channel ?? 'undefined').toLowerCase(),
    severity: 'ERROR',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Canal no soportado. Solo Slack o Telegram en MVP.',
    timestamp: new Date().toISOString()
  }
}];

const input = $json ?? {};
const nowIso = new Date().toISOString();

const eventType = String(input.event_type ?? input.event ?? input.action ?? "ops_notification_event").trim() || "ops_notification_event";
const statusRaw = String(input.status ?? input.result ?? "").trim();

let resultValue = statusRaw ? statusRaw.toLowerCase() : "";
if (!resultValue) {
  if (eventType.includes("sent")) resultValue = "success";
  else if (eventType.includes("error") || eventType.includes("unsupported")) resultValue = "error";
  else resultValue = "unknown";
}

const executionId = String(
  input.execution_id
  ?? input.logical_execution_id
  ?? input.meta?.execution_id
  ?? input.execution?.id
  ?? $execution?.id
  ?? ""
);

const channelValue = String(
  input.channel
  ?? input.notification?.channel
  ?? ""
).trim().toLowerCase();

const severityValue = String(
  input.severity
  ?? input.derived?.severity
  ?? ""
).trim().toUpperCase();

return [{
  json: {
    execution_id: executionId,
    correlation_id: String(input.correlation_id ?? ""),
    action: eventType,
    event_type: eventType,
    status: resultValue,
    result: resultValue,
    channel: channelValue,
    severity: severityValue,
    timestamp: String(input.timestamp ?? nowIso),
    source_workflow: "ops-reporting-alerts"
  }
}];

const input = $json ?? {};
const nowIso = new Date().toISOString();
const severity = String(input.severity ?? input.derived?.severity ?? 'CRITICAL').trim().toUpperCase() || 'CRITICAL';
const eventType = String(input.event_type ?? input.event ?? input.action ?? 'ops_alert_critical').trim() || 'ops_alert_critical';
const correlationId = String(input.correlation_id ?? input.execution_id ?? input.logical_execution_id ?? '').trim();
const executionId = String(input.execution_id ?? input.logical_execution_id ?? input.meta?.execution_id ?? '').trim();
const contractId = String(input.Contrato_ID ?? input.contract_id ?? input.contractId ?? input.contracto_id ?? input.contract ?? '').trim();
const adId = String(input.Ad_ID ?? input.ad_id ?? input.adId ?? '').trim();
const motive = String(input.message_text ?? input.message ?? input.derived?.reason ?? input.derived?.alert_reason ?? '').trim() || 'CRITICAL: vencidos sin pausar';
const createdAt = String(input.timestamp ?? input.created_at ?? input.derived?.executed_at ?? nowIso);
const alertId = String(input.alert_id ?? input.Alerta_ID ?? `${correlationId || executionId || 'ops'}-${Date.now()}`);

return [{
  json: {
    Alerta_ID: alertId,
    Severidad: severity,
    Contrato_ID: contractId,
    Ad_ID: adId,
    Motivo: motive,
    Correlation_ID: correlationId,
    Creada_At: createdAt,
    Estado: 'Abierta',
    source_workflow: 'ops-reporting-alerts',
    event_type: eventType,
    execution_id: executionId
  }
}];
